import express from 'express'
import { config } from './config'

const app = express()
const PORT = config.port || 3000

app.get('/', (req, res) => {
  res.json({ message: 'Hello World' })
})

app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`)
})
